var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"동력부 85% 손상! 더 이상 충격을 받게 될 경우 배터리 유폭의 위험이 있음!","JPN":"動力部85％損傷。これ以上衝撃を受けるとバッテリー誘爆の危険あり。","ENG":"85% damage to the engine! Any more impact will cause the batteries to explode!","TWN":"動力部受損85%！若繼續受到衝擊，將會發生電池爆炸的危險！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GAP_BLACK_NULL_NULL","text":{"KOREA":"후훗, 날 이렇게까지 몰아붙이다니. 굉장한 호적수로군!","JPN":"ふふっ、私をここまで追い詰めるとは。なかなかの敵だな！","ENG":"Hah hah. You're pretty good, pressing me so hard like this!","TWN":"呵呵，竟然能把我逼到這種地步，真是個強勁的好對手！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"GAP_BLACK_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아앗, 이 오토튠이 잔뜩 들어간 목소린......설마?","JPN":"あっ、このオートチューンを使ったような声……まさか？","ENG":"Ah, this electronically distorted voice! Can it be him?","TWN":"啊啊，這個透過變聲器的聲音……難道是？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배님! 선배님이 안에 타고 계신 거 맞죠?!","JPN":"先輩！　先輩がここに乗っているんですか！？","ENG":"Dark! Is that you in there?","TWN":"前輩！是你坐在機器人裡面嗎？！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"하하...... 후배님을 이렇게 다시 만나다니.","JPN":"はは……後輩にこんなところで会えるとは。","ENG":"Hah hah. We met again, Lone.","TWN":"哈哈……竟然會這樣再見到後輩。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"이거 참 부끄러운 걸.","JPN":"少し恥ずかしいな。","ENG":"This is embarrassing.","TWN":"真是丟臉啊。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"아직은 이런 식으로 다시 만나고 싶지 않았는데 말이야.","JPN":"まだこんな風に会いたくはなかったのだが。","ENG":"I didn't want to see you like this... yet.","TWN":"我還真不想用這種方式和妳重逢呢。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"어째서 여기 계신 거죠?!","JPN":"どうしてここにいるんですか！？","ENG":"What are you doing here?","TWN":"你為什麼會在這裡？！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"세계를 정복하러 가신 게 아니었나요?","JPN":"世界を征服しに行ったのでは？","ENG":"I thought you'd be busy dominating the world.","TWN":"你不是踏上征服世界的道路了嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"하하, 물론이지. 하지만 더 이상 폭력이 아닌 흥겨운 비트로 세계를 정복하는 것이 나의 원대한 꿈이라네.","JPN":"はは、もちろんだ。しかし、暴力ではなく、楽しいビートで世界を征服するのが私の夢なのだ。","ENG":"Hah hah, yes, I am. It's just that I'm not trying to dominate it with force; I'm trying to dominate it with rhythm.","TWN":"哈哈，當然啊。但不是用暴力，我的偉大夢想是用歡樂的節奏去征服世界。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"미워하고 부수는 것만이...... 세계정복을 이룰 수 있는 유일한 길은 아니니까.","JPN":"憎しみ壊すことだけが……世界征服を成せる唯一の道ではないからな。","ENG":"Hatred and destruction aren't the only solutions to world domination.","TWN":"仇恨和破壞……並不是征服世界的唯一一條路。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"하지만 후배님이 위험에 처하는 걸 그냥 두고 볼 수는 없었지.","JPN":"しかし、後輩が危機的状況にあるのを見過ごすことはできなかった。","ENG":"But then I saw you in danger. I couldn't just stand aside.","TWN":"只是看到後輩身陷於危險中，我不能置之不理。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"다행히 너무 늦지는 않은 것 같군.","JPN":"幸い手遅れにならずに済んだようだ。","ENG":"I'm glad I'm not late.","TWN":"幸好我來得不算太晚。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"죄송해요, 선배님. 제가...... 제가 바보같이 구는 바람에!","JPN":"ごめんなさい、先輩。私……私がバカだから！","ENG":"I'm sorry, Dark. I... I've caused all this, like the fool I am!","TWN":"對不起，前輩。都怪我……都怪我太愚蠢！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그렇게...... 슬픈 표정 짓지 말게.","JPN":"そんな……悲しい顔をしないでくれ。","ENG":"Please don't fret.","TWN":"不要……露出那麼悲傷的表情。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"난 후배님이 더 이상 꿈을 위해 누군가를, 그리고 자신을 해치지 않길 바랄 뿐이야.","JPN":"私は後輩がこれ以上夢のために誰かを、そして自分を傷つけることがないよう願うだけだ。","ENG":"I just don't want you to hurt others or yourself for the sake of your dreams.","TWN":"我只希望後輩不要再為了自己的夢想傷害別人，也傷害自己了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};